```

Next, create a file named `index.js` and paste the following code:

```javascript
const { Client, Intents } = require('discord.js');
const { token } = require('./config.json');

const client = new Client({
  intents: [
    Intents.FLAGS.Guilds,
    Intents.FLAGS.GuildMessages,
    Intents.FLAGS.MessageContent,
    Intents.FLAGS.MessageReaction,
    Intents.FLAGS.DirectMessages,
  ],
});

client.once('ready', () => {
  console.log('Ready!');
});

client.on('interactionCreate', async (interaction) => {
  if (!interaction.isCommand()) return;

  if (interaction.commandName === 'ban') {
    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return interaction.reply({
        content: 'You do not have permission to use this command.',
        ephemeral: true,
      });
    }

    const member = interaction.options.getMember('member');
    if (!member) {
      return interaction.reply({
        content: 'Please provide a valid member to ban.',
        ephemeral: true,
      });
    }

    await member.ban();
    return interaction.reply({
      content: `${member.user.tag} has been banned.`,
    });
  }
});

